use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
use sqlrustgo::{parse, ExecutionEngine, MemoryStorage};
use std::sync::Arc;

fn setup_engine(size: usize) -> ExecutionEngine {
    let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
    engine
        .execute(parse("CREATE TABLE orders (id INTEGER, amount INTEGER)").unwrap())
        .unwrap();

    for i in 0..size {
        engine
            .execute(parse(&format!("INSERT INTO orders VALUES ({}, {})", i, i * 10)).unwrap())
            .unwrap();
    }
    engine
}

fn bench_aggregate_count(c: &mut Criterion) {
    let mut group = c.benchmark_group("aggregate_count");

    for size in [100, 1000, 10000] {
        let mut engine = setup_engine(size);

        group.bench_with_input(BenchmarkId::new("count_star", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT COUNT(*) FROM orders").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

fn bench_aggregate_sum(c: &mut Criterion) {
    let mut group = c.benchmark_group("aggregate_sum");

    for size in [100, 1000, 10000] {
        let mut engine = setup_engine(size);

        group.bench_with_input(BenchmarkId::new("sum_amount", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT SUM(amount) FROM orders").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

fn bench_aggregate_avg(c: &mut Criterion) {
    let mut group = c.benchmark_group("aggregate_avg");

    for size in [100, 1000, 10000] {
        let mut engine = setup_engine(size);

        group.bench_with_input(BenchmarkId::new("avg_amount", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT AVG(amount) FROM orders").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

fn bench_aggregate_min_max(c: &mut Criterion) {
    let mut group = c.benchmark_group("aggregate_min_max");

    for size in [100, 1000, 10000] {
        let mut engine = setup_engine(size);

        group.bench_with_input(BenchmarkId::new("min_amount", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT MIN(amount) FROM orders").unwrap())
                    .unwrap()
            });
        });

        group.bench_with_input(BenchmarkId::new("max_amount", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT MAX(amount) FROM orders").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

fn bench_aggregate_multiple(c: &mut Criterion) {
    let mut group = c.benchmark_group("aggregate_multiple");

    for size in [100, 1000] {
        let mut engine = setup_engine(size);

        group.bench_with_input(BenchmarkId::new("count_sum_avg", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(
                        parse("SELECT COUNT(*), SUM(amount), AVG(amount) FROM orders").unwrap(),
                    )
                    .unwrap()
            });
        });
    }

    group.finish();
}

criterion_group!(
    benches,
    bench_aggregate_count,
    bench_aggregate_sum,
    bench_aggregate_avg,
    bench_aggregate_min_max,
    bench_aggregate_multiple
);
criterion_main!(benches);

//! v1.4.0 CBO Performance Benchmarks
//!
//! Benchmarks for comparing CBO (Cost-Based Optimization) performance
//! Target: Verify CBO optimization effectiveness
//!
//! Run: cargo bench --bench bench_cbo

use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
use sqlrustgo::{parse, ExecutionEngine, MemoryStorage};
use std::sync::Arc;

fn setup_table(engine: &mut ExecutionEngine, table_name: &str, rows: usize) {
    engine
        .execute(
            parse(&format!(
                "CREATE TABLE {} (id INTEGER, value INTEGER, name TEXT, category TEXT)",
                table_name
            ))
            .unwrap(),
        )
        .unwrap();

    for i in 0..rows {
        engine
            .execute(
                parse(&format!(
                    "INSERT INTO {} VALUES ({}, {}, 'name_{}', 'cat_{}')",
                    table_name,
                    i,
                    i % 100,
                    i,
                    i % 10
                ))
                .unwrap(),
            )
            .unwrap();
    }
}

fn setup_join_tables(engine: &mut ExecutionEngine, t1_rows: usize, t2_rows: usize) {
    engine
        .execute(parse("CREATE TABLE t1 (id INTEGER, value INTEGER, category TEXT)").unwrap())
        .unwrap();
    engine
        .execute(parse("CREATE TABLE t2 (id INTEGER, name TEXT, category TEXT)").unwrap())
        .unwrap();

    for i in 0..t1_rows {
        engine
            .execute(
                parse(&format!(
                    "INSERT INTO t1 VALUES ({}, {}, 'cat_{}')",
                    i,
                    i % 50,
                    i % 10
                ))
                .unwrap(),
            )
            .unwrap();
    }

    for i in 0..t2_rows {
        engine
            .execute(
                parse(&format!(
                    "INSERT INTO t2 VALUES ({}, 'name_{}', 'cat_{}')",
                    i,
                    i,
                    i % 10
                ))
                .unwrap(),
            )
            .unwrap();
    }
}

// ============================================================================
// CBO: Join Method Selection
// ============================================================================

fn bench_cbo_join_method(c: &mut Criterion) {
    let mut group = c.benchmark_group("cbo_join");

    // Small inner table - hash join should be preferred
    for size in [1000, 10000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_join_tables(&mut engine, size, 100);

        group.bench_with_input(
            BenchmarkId::new("small_inner", size),
            &size,
            |b, _| {
                b.iter(|| {
                    engine
                        .execute(
                            parse("SELECT t1.id, t1.value, t2.name FROM t1 JOIN t2 ON t1.category = t2.category")
                                .unwrap(),
                        )
                        .unwrap()
                });
            },
        );
    }

    // Large inner table - nested loop might be preferred
    for size in [100, 1000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_join_tables(&mut engine, size, size * 10);

        group.bench_with_input(
            BenchmarkId::new("large_inner", size),
            &size,
            |b, _| {
                b.iter(|| {
                    engine
                        .execute(
                            parse("SELECT t1.id, t1.value, t2.name FROM t1 JOIN t2 ON t1.category = t2.category")
                                .unwrap(),
                        )
                        .unwrap()
                });
            },
        );
    }

    group.finish();
}

// ============================================================================
// CBO: Index Scan vs Full Scan
// ============================================================================

fn bench_cbo_index_vs_scan(c: &mut Criterion) {
    let mut group = c.benchmark_group("cbo_scan");

    // High selectivity (small result) - index scan preferred
    for size in [1000, 10000, 100000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_table(&mut engine, "t1", size);

        group.bench_with_input(BenchmarkId::new("high_selectivity", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT * FROM t1 WHERE id = 50").unwrap())
                    .unwrap()
            });
        });
    }

    // Low selectivity (large result) - full scan preferred
    for size in [1000, 10000, 100000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_table(&mut engine, "t1", size);

        group.bench_with_input(BenchmarkId::new("low_selectivity", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT * FROM t1 WHERE value > 10").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

// ============================================================================
// CBO: Aggregation Method
// ============================================================================

fn bench_cbo_aggregation(c: &mut Criterion) {
    let mut group = c.benchmark_group("cbo_aggregate");

    // Small group count - hash aggregate
    for size in [1000, 10000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_table(&mut engine, "t1", size);

        group.bench_with_input(BenchmarkId::new("few_groups", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT category, COUNT(*) FROM t1 GROUP BY category").unwrap())
                    .unwrap()
            });
        });
    }

    // Many groups - sort aggregate
    for size in [1000, 10000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_table(&mut engine, "t1", size);

        group.bench_with_input(BenchmarkId::new("many_groups", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT id, SUM(value) FROM t1 GROUP BY id").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

// ============================================================================
// CBO: Complex Query Planning
// ============================================================================

fn bench_cbo_complex_query(c: &mut Criterion) {
    let mut group = c.benchmark_group("cbo_complex");

    // Multi-join query
    for size in [100, 1000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_table(&mut engine, "t1", size);
        setup_table(&mut engine, "t2", size);

        group.bench_with_input(
            BenchmarkId::new("multi_join", size),
            &size,
            |b, _| {
                b.iter(|| {
                    engine
                        .execute(
                            parse("SELECT t1.id, t1.value, t2.name FROM t1 JOIN t2 ON t1.category = t2.category WHERE t1.value > 50")
                                .unwrap(),
                        )
                        .unwrap()
                });
            },
        );
    }

    // Subquery optimization
    for size in [100, 1000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_table(&mut engine, "t1", size);

        group.bench_with_input(BenchmarkId::new("subquery", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(
                        parse("SELECT * FROM t1 WHERE id IN (SELECT id FROM t1 WHERE value > 50)")
                            .unwrap(),
                    )
                    .unwrap()
            });
        });
    }

    group.finish();
}

// ============================================================================
// Vectorization Performance
// ============================================================================

fn bench_vectorization_batch(c: &mut Criterion) {
    let mut group = c.benchmark_group("vectorization");

    for size in [1000, 10000, 100000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_table(&mut engine, "t1", size);

        // Batch processing test
        group.bench_with_input(BenchmarkId::new("batch_scan", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT id, value FROM t1").unwrap())
                    .unwrap()
            });
        });

        // SIMD-like operations test
        group.bench_with_input(BenchmarkId::new("simd_filter", size), &size, |b, _| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT * FROM t1 WHERE value > 50").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

criterion_group!(
    benches,
    // CBO Join (4 benchmarks)
    bench_cbo_join_method,
    // CBO Scan (6 benchmarks)
    bench_cbo_index_vs_scan,
    // CBO Aggregate (4 benchmarks)
    bench_cbo_aggregation,
    // CBO Complex (4 benchmarks)
    bench_cbo_complex_query,
    // Vectorization (6 benchmarks)
    bench_vectorization_batch,
);
criterion_main!(benches);

//! Insert Benchmark - benches/bench_insert.rs
//!
//! INSERT performance benchmark for SQLRustGo using StorageEngine

use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
use sqlrustgo_storage::{ColumnDefinition, MemoryStorage, StorageEngine, TableInfo};
use sqlrustgo_types::Value;

/// Generate test data rows
fn generate_rows(count: usize) -> Vec<Vec<Value>> {
    (0..count).map(|i| vec![Value::Integer(i as i64)]).collect()
}

/// Create test table info
fn create_table_info() -> TableInfo {
    TableInfo {
        name: "bench".to_string(),
        columns: vec![ColumnDefinition {
            name: "id".to_string(),
            data_type: "INTEGER".to_string(),
            nullable: false,
        }],
    }
}

/// Benchmark INSERT with different data sizes using MemoryStorage
fn bench_insert_sizes(c: &mut Criterion) {
    let mut group = c.benchmark_group("insert");

    for size in [1_000, 10_000, 100_000] {
        group.bench_with_input(BenchmarkId::from_parameter(size), &size, |b, &size| {
            b.iter(|| {
                let mut storage = MemoryStorage::new();
                storage.create_table(&create_table_info()).unwrap();
                let rows = generate_rows(size);
                storage.insert("bench", rows).unwrap();
            });
        });
    }

    group.finish();
}

/// Benchmark batch INSERT performance
fn bench_insert_batch(c: &mut Criterion) {
    let mut group = c.benchmark_group("insert_batch");

    for batch_size in [10, 100, 1000] {
        let total_rows = 10_000;
        group.bench_with_input(
            BenchmarkId::from_parameter(batch_size),
            &batch_size,
            |b, &batch_size| {
                b.iter(|| {
                    let mut storage = MemoryStorage::new();
                    storage.create_table(&create_table_info()).unwrap();

                    let mut batch = Vec::with_capacity(batch_size);
                    for i in 0..total_rows {
                        batch.push(vec![Value::Integer(i as i64)]);
                        if batch.len() >= batch_size {
                            storage.insert("bench", std::mem::take(&mut batch)).unwrap();
                            batch = Vec::with_capacity(batch_size);
                        }
                    }
                    if !batch.is_empty() {
                        storage.insert("bench", batch).unwrap();
                    }
                });
            },
        );
    }

    group.finish();
}

/// Benchmark INSERT with multiple columns
fn bench_insert_multi_column(c: &mut Criterion) {
    let mut group = c.benchmark_group("insert_multi_column");

    let table_info = TableInfo {
        name: "bench".to_string(),
        columns: vec![
            ColumnDefinition {
                name: "id".to_string(),
                data_type: "INTEGER".to_string(),
                nullable: false,
            },
            ColumnDefinition {
                name: "name".to_string(),
                data_type: "TEXT".to_string(),
                nullable: true,
            },
            ColumnDefinition {
                name: "value".to_string(),
                data_type: "INTEGER".to_string(),
                nullable: true,
            },
        ],
    };

    for size in [1_000, 10_000] {
        group.bench_with_input(BenchmarkId::from_parameter(size), &size, |b, &size| {
            b.iter(|| {
                let mut storage = MemoryStorage::new();
                storage.create_table(&table_info).unwrap();

                let rows: Vec<Vec<Value>> = (0..size)
                    .map(|i| {
                        vec![
                            Value::Integer(i as i64),
                            Value::Text(format!("user_{}", i)),
                            Value::Integer((i * 10) as i64),
                        ]
                    })
                    .collect();
                storage.insert("bench", rows).unwrap();
            });
        });
    }

    group.finish();
}

/// Measure throughput (rows/s) for 100k insert
fn bench_insert_throughput(c: &mut Criterion) {
    let mut group = c.benchmark_group("insert_throughput");

    group.bench_function("100k_rows", |b| {
        b.iter(|| {
            let mut storage = MemoryStorage::new();
            storage.create_table(&create_table_info()).unwrap();
            let rows = generate_rows(100_000);
            storage.insert("bench", rows).unwrap();
        });
    });

    group.finish();
}

criterion_group!(
    benches,
    bench_insert_sizes,
    bench_insert_batch,
    bench_insert_multi_column,
    bench_insert_throughput
);
criterion_main!(benches);

//! Scan Benchmark for SQLRustGo
//!
//! Benchmarks for full table scan operations.

use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
use sqlrustgo::{parse, ExecutionEngine, MemoryStorage};
use std::sync::Arc;

fn setup_engine_with_data(rows: usize) -> ExecutionEngine {
    let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
    engine
        .execute(parse("CREATE TABLE scan_bench (id INTEGER, name TEXT, value INTEGER)").unwrap())
        .unwrap();

    for i in 0..rows {
        engine
            .execute(
                parse(&format!(
                    "INSERT INTO scan_bench VALUES ({}, 'name_{}', {})",
                    i,
                    i % 1000,
                    i
                ))
                .unwrap(),
            )
            .unwrap();
    }

    engine
}

fn bench_scan_1k(c: &mut Criterion) {
    let mut engine = setup_engine_with_data(1_000);

    c.bench_function("scan_1k", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT * FROM scan_bench").unwrap())
                .unwrap()
        });
    });
}

fn bench_scan_10k(c: &mut Criterion) {
    let mut engine = setup_engine_with_data(10_000);

    c.bench_function("scan_10k", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT * FROM scan_bench").unwrap())
                .unwrap()
        });
    });
}

fn bench_scan_100k(c: &mut Criterion) {
    let mut engine = setup_engine_with_data(100_000);

    c.bench_function("scan_100k", |b| {
        b.iter(|| {
            engine
                .execute(parse("SELECT * FROM scan_bench").unwrap())
                .unwrap()
        });
    });
}

fn bench_scan_with_filter(c: &mut Criterion) {
    let mut group = c.benchmark_group("scan_with_filter");

    for size in [1_000, 10_000, 100_000] {
        let mut engine = setup_engine_with_data(size);

        group.bench_with_input(BenchmarkId::from_parameter(size), &size, |b, &_size| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT * FROM scan_bench WHERE value > 500").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

fn bench_scan_projection(c: &mut Criterion) {
    let mut group = c.benchmark_group("scan_projection");

    for size in [1_000, 10_000, 100_000] {
        let mut engine = setup_engine_with_data(size);

        group.bench_with_input(BenchmarkId::from_parameter(size), &size, |b, &_size| {
            b.iter(|| {
                engine
                    .execute(parse("SELECT id, value FROM scan_bench").unwrap())
                    .unwrap()
            });
        });
    }

    group.finish();
}

criterion_group!(
    benches,
    bench_scan_1k,
    bench_scan_10k,
    bench_scan_100k,
    bench_scan_with_filter,
    bench_scan_projection
);
criterion_main!(benches);

//! v1.3.0 Performance Benchmarks
//!
//! Benchmarks for TableScan, Filter, and HashJoin operations.
//! Target: 18 benchmarks
//! Threshold: +20% latency

use criterion::{criterion_group, criterion_main, BenchmarkId, Criterion};
use sqlrustgo::{parse, ExecutionEngine, MemoryStorage};
use std::sync::Arc;

fn setup_table(engine: &mut ExecutionEngine, table_name: &str, rows: usize) {
    engine
        .execute(
            parse(&format!(
                "CREATE TABLE {} (id INTEGER, value INTEGER, name TEXT)",
                table_name
            ))
            .unwrap(),
        )
        .unwrap();

    for i in 0..rows {
        engine
            .execute(
                parse(&format!(
                    "INSERT INTO {} VALUES ({}, {}, 'name_{}')",
                    table_name,
                    i,
                    i % 100,
                    i
                ))
                .unwrap(),
            )
            .unwrap();
    }
}

// ============================================================================
// TableScan Benchmarks (6 benchmarks)
// ============================================================================

fn bench_tablescan_full(c: &mut Criterion) {
    let mut group = c.benchmark_group("tablescan_full");

    for size in [100, 1000, 10000] {
        let mut engine = ExecutionEngine::new(Arc::new(MemoryStorage::new()));
        setup_table(&mut engine, "t1", size);

        group.bench_with_input(BenchmarkId::new("full_scan", size), &size, |b, _| {
            b.iter(|| engine.execute(parse("SELECT * FROM t1").unwrap()).unwrap());
