/// SortMergeJoinVolcanoExecutor - Sort-Merge Join algorithm implementation
/// Alternative to HashJoin, works best when inputs are already sorted by join keys
#[allow(dead_code)]
pub struct SortMergeJoinVolcanoExecutor {
