        let left = Box::new(MockVolcanoExecutor::with_data(vec![
            vec![Value::Integer(1)],
            vec![Value::Integer(2)],
        ]));
        let right = Box::new(MockVolcanoExecutor::with_data(vec![
            vec![Value::Integer(10)],
            vec![Value::Integer(20)],
