    struct MockExecutorWithData {
        data: Vec<Vec<Value>>,
        idx: usize,
        initialized: bool,
        schema: Schema,
    }

    impl MockExecutorWithData {
        fn new(data: Vec<Vec<Value>>) -> Self {
            Self {
                data,
                idx: 0,
                initialized: false,
                schema: Schema::empty(),
            }
        }
    }

