        let _ = remove_dir_all(&temp_dir);

        {
            let mut storage = FileStorage::new(temp_dir.clone()).unwrap();

            // Insert a table and create index
            let table_data = TableData {
                info: TableInfo {
                    name: "users".to_string(),
