        assert_eq!(parse_sql_literal("FALSE"), Value::Boolean(false));
        assert_eq!(parse_sql_literal("42"), Value::Integer(42));
        assert_eq!(parse_sql_literal("3.14"), Value::Float(3.14));
        assert_eq!(
            parse_sql_literal("'hello'"),
            Value::Text("hello".to_string())
        );
    }
}

